steps.script:
var p = "user://saves/ScenarioDialogSave.w40ksave"
if FileAccess.file_exists(p):
	DirAccess.remove_absolute(p)
if FileAccess.file_exists(p.replace(".w40ksave", ".meta")):
	DirAccess.remove_absolute(p.replace(".w40ksave", ".meta"))
return true

var main = tree.root.get_node("/root/Main")
var m = main.get_node_or_null("SettingsMenu")
if m == null or not m.visible:
	main._run_pause_menu_cascade(true)
return true

var menu = tree.root.get_node("/root/Main/SettingsMenu")
var btn = null
var stack = [menu]
while stack.size() > 0:
	var n = stack.pop_back()
	for c in n.get_children():
		stack.append(c)
	if n is Button and "Save" in n.text and "Load" in n.text:
		btn = n
if btn == null or not btn.visible:
	return false
btn.pressed.emit()
return true

var d = tree.root.get_node("/root/Main/SaveLoadDialog")
var found = false
for s in d.save_files_data:
	if s.get("display_name", "") == "ScenarioDialogSave" and s.get("source", "") == "local":
		found = true
return found
